class EnfantStatique extends StatelessWidget {
  final String texte;
  const EnfantStatique({Key? key, required this.texte}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return Text(texte);
  }
}

// Et dans ParentWidget : utiliser const si possible
// const EnfantStatique(texte: _texteStatique) // mais _texteStatique n'est pas constant
// Autre solution : utiliser un widget avec const constructeur quand les données sont constantes
```
Explication : En transformant EnfantStatique en StatelessWidget et en utilisant le mot-clé `const` sur son constructeur lorsque les arguments sont constants, Flutter peut réutiliser l'instance précédente du widget au lieu d'en recréer une nouvelle. Si ce n'est pas possible (comme ici avec _texteStatique qui n'est pas final), la meilleure pratique avec setState() est de découper l'arbre en petits widgets pour limiter la portée du rebuild : placer le compteur dans son propre StatefulWidget pour que setState() ne rafraîchisse que cette partie.

```dart
class _MinuteurState extends State<Minuteur> {
  int _secondesRestantes = 60;
  Timer? _timer;

  void _demarrer() {
    // Éviter de créer un deuxième timer si un tourne déjà
    if (_timer != null && _timer!.isActive) return;
    // Éviter de démarrer si déjà à 0
    if (_secondesRestantes <= 0) return;

    _timer = Timer.periodic(Duration(seconds: 1), (timer) {
      setState(() {
        if (_secondesRestantes > 0) {
          _secondesRestantes--;
        }
        // Arrêter le timer quand on arrive à 0
        if (_secondesRestantes == 0) {
          _timer?.cancel();
          _timer = null;
        }
      });
    });
  }

  void _pause() {
    _timer?.cancel();
    _timer = null;
  }

  void _reinitialiser() {
    _pause(); // arrêter le timer s'il tourne
    setState(() {
      _secondesRestantes = 60;
    });
  }

  String _formaterTemps() {
    int minutes = _secondesRestantes ~/ 60;
    int secondes = _secondesRestantes % 60;
    return '${minutes.toString().padLeft(2, '0')}:${secondes.toString().padLeft(2, '0')}';
  }

  @override
  void dispose() {
    _timer?.cancel(); // nettoyage important pour éviter les fuites mémoire
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text(_formaterTemps(), style: TextStyle(fontSize: 60)),
        Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            ElevatedButton(onPressed: _demarrer, child: Text('Démarrer')),
            ElevatedButton(onPressed: _pause, child: Text('Pause')),
            ElevatedButton(onPressed: _reinitialiser, child: Text('Réinitialiser')),
          ],
        )
      ],
    );
  }
}
```
Commentaires : 
- Utilisation de `Timer? _timer` pour garder une référence et pouvoir annuler.
- Vérification `_timer?.isActive` pour éviter les doubles démarrages.
- Méthode `dispose` indispensable pour annuler le timer quand le widget est retiré de l'arbre.
- `setState` est appelé chaque seconde pour mettre à jour l'affichage.
